function Get-ProcessList {
    param(
        [string]$Filter = '',
        [int]$Top = 50
    )
    $procs = Get-Process | Select-Object Id, ProcessName, CPU, WorkingSet, StartTime
    if ($Filter) {
        $procs = $procs | Where-Object { $_.ProcessName -like "*$Filter*" }
    }
    $procs = $procs | Sort-Object CPU -Descending | Select-Object -First $Top
    $out = @($procs | ForEach-Object {
        @{
            pid = $_.Id
            name = $_.ProcessName
            cpu = $_.CPU
            memory_mb = [math]::Round($_.WorkingSet / 1MB, 2)
            started = if ($_.StartTime) { $_.StartTime.ToString('o') } else { $null }
        }
    })
    return @{ count = $out.Count; processes = $out } | ConvertTo-Json -Depth 3
}

Get-ProcessList -Filter '{{filter}}' -Top {{top}}
